#include <bits/stdc++.h>
using namespace std;
bool a[100001];
int main(){
    int n;
    cin>>n;
    a[1]=false;
    for(int i=2;i<=100001;i++)a[i]=true;
    for(int i=2;i<=100001/2+1;i++){
        if(a[i]){
            for(int j=i+i;j<=100001;j+=i){
                a[j]=false;
            }
        }
    }
    int s;
    for(int i=1;i<=n;i++){
        cin>>s;
        if(a[s])cout<<s<<' ';
    }
    return 0;
}
